external_knowledge:
; The 'employment sectors' refer to the categories of jobs that people are employed in; 
; The 'geographical data records' are the number of unique records of geographical information in the economic indicators; 
; The 'access logs' represent the number of times users access the system.

sql:
SELECT population_count 
FROM population_stats 
WHERE obs_id = (SELECT obs_id FROM economic_indicators WHERE year = 1948);

SELECT 
  (SELECT employment_count FROM employment_stats WHERE obs_id = 0) AS total_employment_count,
  (SELECT gnp_per_capita FROM gnp_stats WHERE obs_id = 0) AS average_gnp_per_capita;

SELECT AVG(gnp_per_capita) AS average_gnp_per_capita
FROM gnp_stats
WHERE gnp_growth_rate > 3.0;
